  ('disabled-6f0ba476-moex-00487', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '財貨x的Marshallian需求價格彈性為−0.51，財貨y的Marshallian需求價 格彈性為−7.40，應用這些訊息以及反彈性法則計算兩財貨商品稅稅率，下 列敘述何者正確？', '["必須兩財貨的替代效果皆為零或很微小", "兩財貨的相對稅率等於兩財貨相對的Marshallian需求價格彈性", "財貨x和y必須為替代財", "財貨x和y之間必須無關聯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00488', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '假設休閒為正常財，在稅收相同的情況下，課徵比例工資所得稅與定額稅， 對勞動者的稅後效用水準之影響大小為何？', '["課徵定額稅下的稅後效用水準大於課徵比例工資所得稅下的稅後效用 水準", "課徵定額稅下的稅後效用水準小於課徵比例工資所得稅下的稅後效用 水準", "課徵定額稅下的稅後效用水準等於課徵比例工資所得稅下的稅後效用 水準", "無法比較"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00489', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-3e700a6a', 'sub-disabled-6f0ba476-06', NULL, 'single_choice', '兩期消費理論模型，且消費為正常財的假設下，政府對儲蓄的利息收入課 徵所得稅且利息支出可以扣除，若其所得效果小於替代效果，則儲蓄者的 當期消費會如何變化？', '["當期消費增加", "當期消費減少", "當期消費不變", "當期消費可能增加也可能減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "6f34d20004a3", "answer_pdf_sha1": "db3ff28e6084", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
